// src/checkout/checkout.ts
export class Checkout {
  constructor(private payments: Payments, private orders: Orders) {}
  async submitOrder(order: Order) {
    const idempotencyKey = `order:${order.id}:attempt:${order.attempt}`;
    const auth = await this.payments.authorize(order.total, order.card, idempotencyKey);
    if (!auth.ok) return this.orders.markDeclined(order, auth.reason);
    const capture = await this.payments.capture(auth.id, idempotencyKey);
    return this.orders.markPaid(order, capture.id);
  }
}

// src/payments/payments.ts
import { withRetry } from './retry';
import { Gateway } from './gateway';
export class Payments {
  constructor(private gateway: Gateway) {}
  async authorize(amount: number, card: Card, idempotencyKey: string) {
    return this.gateway.authorize({ amount, card, idempotencyKey });
  }
  async capture(authId: string, idempotencyKey: string) {
    // capture is wrapped so a transient gateway timeout is retried
    return withRetry(() => this.gateway.capture({ authId }));
  }
}

// src/payments/retry.ts
// Retries a gateway call on a transient timeout. NOTE: the closure it retries is
// whatever the caller passed; capture() passes () => gateway.capture({ authId })
// with NO idempotencyKey, so each retry is a brand-new capture to the gateway.
export async function withRetry<T>(fn: () => Promise<T>, tries = 3): Promise<T> {
  let lastErr;
  for (let i = 0; i < tries; i++) {
    try { return await fn(); }
    catch (e) { if (!isTimeout(e)) throw e; lastErr = e; await sleep(200 * (i + 1)); }
  }
  throw lastErr;
}
